const input = $input.first().json;

const appointmentId = input.appointment_id || input.id_agendamento || null;
const patientPhone = input.patient_phone || input.telefone_paciente || null;
const reason = input.reason || input.motivo || null;

if (!appointmentId || !patientPhone) {
  return [{ json: { error: true, message: 'É necessário o ID do agendamento e o telefone do paciente para cancelar.' } }];
}

return [{ json: { appointment_id: parseInt(appointmentId), patient_phone: patientPhone, reason } }];

const result = $input.first().json;

if (result.error) {
  return [{ json: { resultado: result.mensagem } }];
}

if (result.sucesso) {
  return [{ json: { resultado: `✅ ${result.mensagem}` } }];
} else {
  return [{ json: { resultado: `❌ ${result.mensagem}` } }];
}
